using System;
using System.Collections.Generic;
using System.Globalization;
using System.Windows;
using System.Windows.Media;

namespace Ipi.Desktop;

/// <summary>
/// Provider brand glyphs extracted from locally installed @ant-design/icons-svg (MIT).
/// Falls back to a restrained monogram when no matching provider icon exists.
/// </summary>
public sealed class ProviderBrandIcon : FrameworkElement
{
    public static readonly DependencyProperty ProviderProperty = DependencyProperty.Register(
        nameof(Provider), typeof(string), typeof(ProviderBrandIcon), new FrameworkPropertyMetadata(string.Empty, FrameworkPropertyMetadataOptions.AffectsRender));

    public static readonly DependencyProperty LabelProperty = DependencyProperty.Register(
        nameof(Label), typeof(string), typeof(ProviderBrandIcon), new FrameworkPropertyMetadata(string.Empty, FrameworkPropertyMetadataOptions.AffectsRender));

    public static readonly DependencyProperty SizeProperty = DependencyProperty.Register(
        nameof(Size), typeof(double), typeof(ProviderBrandIcon), new FrameworkPropertyMetadata(34.0, FrameworkPropertyMetadataOptions.AffectsMeasure | FrameworkPropertyMetadataOptions.AffectsRender));

    public static readonly DependencyProperty ForegroundProperty = DependencyProperty.Register(
        nameof(Foreground), typeof(Brush), typeof(ProviderBrandIcon), new FrameworkPropertyMetadata(Brushes.White, FrameworkPropertyMetadataOptions.AffectsRender));

    public string Provider { get => (string)GetValue(ProviderProperty); set => SetValue(ProviderProperty, value); }
    public string Label { get => (string)GetValue(LabelProperty); set => SetValue(LabelProperty, value); }
    public double Size { get => (double)GetValue(SizeProperty); set => SetValue(SizeProperty, value); }
    public Brush Foreground { get => (Brush)GetValue(ForegroundProperty); set => SetValue(ForegroundProperty, value); }

    protected override Size MeasureOverride(Size availableSize) => new(Size, Size);
    protected override Size ArrangeOverride(Size finalSize) => new(Size, Size);

    protected override void OnRender(DrawingContext dc)
    {
        base.OnRender(dc);
        var iconKey = ResolveIconKey(Provider);
        if (!string.IsNullOrWhiteSpace(iconKey) && IconPaths.TryGetValue(iconKey, out var paths))
        {
            var scale = Math.Min(ActualWidth, ActualHeight) / 896.0;
            var offsetX = (ActualWidth - 896 * scale) / 2.0;
            var offsetY = (ActualHeight - 896 * scale) / 2.0;
            dc.PushTransform(new TranslateTransform(offsetX, offsetY));
            dc.PushTransform(new ScaleTransform(scale, scale));
            dc.PushTransform(new TranslateTransform(-64, -64));
            foreach (var path in paths)
            {
                try
                {
                    var geometry = Geometry.Parse(path);
                    geometry.Freeze();
                    dc.DrawGeometry(Foreground, null, geometry);
                }
                catch { }
            }
            dc.Pop();
            dc.Pop();
            dc.Pop();
            return;
        }

        DrawMonogram(dc);
    }

    private void DrawMonogram(DrawingContext dc)
    {
        var text = BuildMonogram(Label, Provider);
        var typeface = new Typeface(new FontFamily("Segoe UI Variable Text, Segoe UI"), FontStyles.Normal, FontWeights.SemiBold, FontStretches.Normal);
        var formatted = new FormattedText(
            text,
            CultureInfo.CurrentUICulture,
            FlowDirection.LeftToRight,
            typeface,
            Math.Max(10, ActualWidth * 0.33),
            Foreground,
            VisualTreeHelper.GetDpi(this).PixelsPerDip);
        dc.DrawText(formatted, new Point((ActualWidth - formatted.Width) / 2.0, (ActualHeight - formatted.Height) / 2.0));
    }

    private static string BuildMonogram(string label, string provider)
    {
        var source = string.IsNullOrWhiteSpace(label) ? provider : label;
        var parts = source.Split(new[] { ' ', '/', '-', '_', '(', ')' }, StringSplitOptions.RemoveEmptyEntries);
        if (parts.Length == 0) return "+";
        var first = char.ToUpperInvariant(parts[0][0]).ToString();
        if (parts.Length == 1) return first;
        return first + char.ToUpperInvariant(parts[1][0]);
    }

    private static string ResolveIconKey(string provider)
    {
        if (string.IsNullOrWhiteSpace(provider)) return string.Empty;
        return ProviderToIcon.TryGetValue(provider.Trim().ToLowerInvariant(), out var key) ? key : string.Empty;
    }

